SELECT i.id, i.member_id AS member_id, m.nickname AS member_nickname, i.category, i.content, i.reply, i.status, i.created_datetime AS created_datetime, i.updated_datetime AS updated_datetime FROM tbl_inquiry i LEFT JOIN tbl_member m ON i.member_id = m.id
AND i.status = #{status}
AND i.category = #{category}
AND i.member_id = #{memberId}
ORDER BY i.created_datetime DESC LIMIT #{size} OFFSET (#{page} - 1) * #{size}

SELECT COUNT(*)
FROM tbl_inquiry i


        AND i.status = #{status}


        AND i.category = #{category}


        AND i.member_id = #{memberId}
